/**
 * @suppress
 */
public object FfiConverterSequenceTypeRdpRect: FfiConverterRustBuffer<List<RdpRect>> {
    override fun read(buf: ByteBuffer): List<RdpRect> {
        val len = buf.getInt()
        return List<RdpRect>(len) {
            FfiConverterTypeRdpRect.read(buf)
        }
    }

    override fun allocationSize(value: List<RdpRect>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterTypeRdpRect.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<RdpRect>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterTypeRdpRect.write(it, buf)
        }
    }
}

